`;

for (let item of items) {
  const json = item.json || {};
  const title       = (json.title || 'Untitled').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const source      = (json.source || 'Unknown').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const published   = json.published_date || '—';
  const snippet     = json.snippet ? json.snippet.replace(/</g, '&lt;').replace(/>/g, '&gt;') : '';
  const safeUrl     = (json.url || '#').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  emailBody += `
      <div style="background:#ffffff; border:1px solid #e2e8f0; border-radius:12px; margin:16px 0; padding:20px 24px; box-shadow:0 2px 8px rgba(0,0,0,0.04);">
        <h3 style="margin:0 0 10px; font-size:17px; font-weight:600; color:#1e40af;">
          ${title}
        </h3>
        <div style="color:#64748b; font-size:13.5px;">
          <strong style="color:#334155;">${source}</strong> • ${published}
        </div>
        ${snippet ? `<div style="margin:16px 0; padding:14px; background:#f8fafc; border-radius:8px; border-left:4px solid #a5b4fc; font-size:14px; color:#475569;">${snippet}</div>` : ""}
        <div style="margin-top:12px; font-size:13px; color:#9ca3af;">
          <a href="${safeUrl}" style="color:#3b82f6; text-decoration:none;">→ Read article</a>
        </div>
      </div>`;
}

emailBody += `
    </div>

    <div style="padding:28px 24px; text-align:center; border-top:1px solid #e2e8f0; background:#f8fafc;">
      <p style="margin:0 0 20px; color:#334155; font-size:15px; font-weight:500;">
        All sources verified as correct & relevant?
      </p>
      <a href="YOUR_WEBHOOK_BASE_URL"
         style="display:inline-block; padding:14px 40px; background:#10b981; color:white; text-decoration:none; font-weight:600; font-size:16px; border-radius:10px; box-shadow:0 4px 14px rgba(16,185,129,0.25);">
         Verify All Sources
      </a>
      <p style="margin:16px 0 0; font-size:13px; color:#9ca3af;">
        Confirms all sources are accurate for topic: ${topic}
      </p>
    </div>

    <div style="padding:20px 24px; text-align:center; background:#f8fafc; border-top:1px solid #e2e8f0; font-size:13px; color:#9ca3af;">
      Topic: ${topic} • Verification • ${new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
    </div>
  </div>
</div>`;

const verificationPayload = {
  vid: trackId,
  topic: topic,
  urls: sourceUrls,
  email: userEmail, // Also added to the payload
  status: "pending"
};

return [
  { json: { emailBody, email: userEmail } } // Passing it out of the node here too
];

// inputData = items from previous node
let results = [];

for (let item of items) {
  const topic = item.json.output.topic;
  const links = item.json.output.links;

  for (let link of links) {
    results.push({
      json: {
        topic: topic,
        title: link.title,
        url: link.url,
        source: link.source,
        published_date: link.published_date
      }
    });
  }
}

return results;
